import{_ as t,c as a,o,a1 as i}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse(`{"title":"Échec d'authentification: Dépannage erreur 401 | Antigravity-Manager","description":"Apprenez le mécanisme d'authentification du proxy Antigravity Tools, dépannage des erreurs 401. Localisez le problème dans l'ordre auth_mode, api_key, Header, comprenez les règles du mode auto et l'exemption /healthz, évitez les pièges de priorité des en-têtes.","frontmatter":{"title":"Échec d'authentification: Dépannage erreur 401 | Antigravity-Manager","sidebarTitle":"Résoudre 401 en 3 minutes","subtitle":"401/Échec d'authentification: d'abord auth_mode, ensuite Header","description":"Apprenez le mécanisme d'authentification du proxy Antigravity Tools, dépannage des erreurs 401. Localisez le problème dans l'ordre auth_mode, api_key, Header, comprenez les règles du mode auto et l'exemption /healthz, évitez les pièges de priorité des en-têtes.","tags":["FAQ","Authentification","401","Clé API"],"prerequisite":["start-proxy-and-first-client"],"order":2},"headers":[],"relativePath":"fr/lbjlaq/Antigravity-Manager/faq/auth-401/index.md","filePath":"fr/lbjlaq/Antigravity-Manager/faq/auth-401/index.md"}`),r={name:"fr/lbjlaq/Antigravity-Manager/faq/auth-401/index.md"};function s(d,e,n,l,c,u){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="_401-echec-d-authentification-d-abord-auth-mode-ensuite-header" tabindex="-1">401/Échec d&#39;authentification : d&#39;abord auth_mode, ensuite Header <a class="header-anchor" href="#_401-echec-d-authentification-d-abord-auth-mode-ensuite-header" aria-label="Permalink to &quot;401/Échec d&#39;authentification : d&#39;abord auth_mode, ensuite Header&quot;">​</a></h1><h2 id="ce-que-vous-saurez-faire-a-la-fin" tabindex="-1">Ce que vous saurez faire à la fin <a class="header-anchor" href="#ce-que-vous-saurez-faire-a-la-fin" aria-label="Permalink to &quot;Ce que vous saurez faire à la fin&quot;">​</a></h2><ul><li>Déterminer en 3 minutes si 401 est bloqué par le middleware d&#39;authentification d&#39;Antigravity Tools</li><li>Comprendre les quatre modes de <code>proxy.auth_mode</code> (surtout <code>auto</code>) et leur « valeur effective » dans votre configuration actuelle</li><li>Utiliser le bon en-tête de clé API (et éviter les pièges de priorité des en-têtes) pour faire passer les requêtes</li></ul><h2 id="votre-situation-actuelle" tabindex="-1">Votre situation actuelle <a class="header-anchor" href="#votre-situation-actuelle" aria-label="Permalink to &quot;Votre situation actuelle&quot;">​</a></h2><p>Le client appelle le proxy local et reçoit une erreur <code>401 Unauthorized</code> :</p><ul><li>Python/OpenAI SDK : lance <code>AuthenticationError</code></li><li>curl : renvoie <code>HTTP/1.1 401 Unauthorized</code></li><li>Client HTTP : code d&#39;état de réponse 401</li></ul><h2 id="qu-est-ce-que-401-echec-d-authentification" tabindex="-1">Qu&#39;est-ce que 401/échec d&#39;authentification ? <a class="header-anchor" href="#qu-est-ce-que-401-echec-d-authentification" aria-label="Permalink to &quot;Qu&#39;est-ce que 401/échec d&#39;authentification ?&quot;">​</a></h2><p><strong>401 Unauthorized</strong> dans Antigravity Tools signifie le plus souvent : le proxy a activé l&#39;authentification (déterminée par <code>proxy.auth_mode</code>), mais la requête n&#39;a pas porté de clé API, ou a porté un en-tête prioritaire mais non correspondant, donc <code>auth_middleware()</code> renvoie directement 401.</p><div class="info custom-block"><p class="custom-block-title">Confirmez d&#39;abord si « le proxy bloque »</p><p>La plateforme en amont peut également renvoyer 401, mais cette FAQ traite uniquement du « 401 causé par l&#39;authentification du proxy ». Vous pouvez utiliser d&#39;abord le <code>/healthz</code> ci-dessous pour distinguer rapidement.</p></div><h2 id="depannage-rapide-suivez-cet-ordre" tabindex="-1">Dépannage rapide (suivez cet ordre) <a class="header-anchor" href="#depannage-rapide-suivez-cet-ordre" aria-label="Permalink to &quot;Dépannage rapide (suivez cet ordre)&quot;">​</a></h2><h3 id="etape-1-utiliser-healthz-pour-determiner-«-l-authentification-vous-bloque-t-elle-»" tabindex="-1">Étape 1 : Utiliser <code>/healthz</code> pour déterminer « l&#39;authentification vous bloque-t-elle » <a class="header-anchor" href="#etape-1-utiliser-healthz-pour-determiner-«-l-authentification-vous-bloque-t-elle-»" aria-label="Permalink to &quot;Étape 1 : Utiliser `/healthz` pour déterminer « l&#39;authentification vous bloque-t-elle »&quot;">​</a></h3><p><strong>Pourquoi</strong><code>all_except_health</code> autorise <code>/healthz</code> mais bloque les autres routes ; cela peut vous aider à localiser rapidement si 401 provient de la couche d&#39;authentification du proxy.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Sans aucun en-tête d&#39;authentification</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/healthz</span></span></code></pre></div><p><strong>Ce que vous devriez voir</strong></p><ul><li>Quand <code>auth_mode=all_except_health</code> (ou <code>auto</code> et <code>allow_lan_access=true</code>) : renvoie généralement <code>200</code></li><li>Quand <code>auth_mode=strict</code> : renverra <code>401</code></li></ul><div class="tip custom-block"><p class="custom-block-title"><code>/healthz</code> est GET dans la couche de routage</p><p>Le proxy enregistre <code>GET /healthz</code> dans le routage (voir <code>src-tauri/src/proxy/server.rs</code>).</p></div><hr><h3 id="etape-2-confirmer-la-«-valeur-effective-»-de-auth-mode-surtout-auto" tabindex="-1">Étape 2 : Confirmer la « valeur effective » de <code>auth_mode</code> (surtout <code>auto</code>) <a class="header-anchor" href="#etape-2-confirmer-la-«-valeur-effective-»-de-auth-mode-surtout-auto" aria-label="Permalink to &quot;Étape 2 : Confirmer la « valeur effective » de `auth_mode` (surtout `auto`)&quot;">​</a></h3><p><strong>Pourquoi</strong><code>auto</code> n&#39;est pas une « stratégie indépendante », il calcule le mode réel à exécuter selon <code>allow_lan_access</code>.</p><table tabindex="0"><thead><tr><th><code>proxy.auth_mode</code></th><th>Condition supplémentaire</th><th>Valeur effective (effective mode)</th></tr></thead><tbody><tr><td><code>off</code></td><td>-</td><td><code>off</code></td></tr><tr><td><code>strict</code></td><td>-</td><td><code>strict</code></td></tr><tr><td><code>all_except_health</code></td><td>-</td><td><code>all_except_health</code></td></tr><tr><td><code>auto</code></td><td><code>allow_lan_access=false</code></td><td><code>off</code></td></tr><tr><td><code>auto</code></td><td><code>allow_lan_access=true</code></td><td><code>all_except_health</code></td></tr></tbody></table><p><strong>Vous pouvez vérifier dans la page GUI API Proxy</strong> : <code>Allow LAN Access</code> et <code>Auth Mode</code>.</p><hr><h3 id="etape-3-confirmer-que-api-key-n-est-pas-vide-et-que-vous-utilisez-la-meme-valeur" tabindex="-1">Étape 3 : Confirmer que <code>api_key</code> n&#39;est pas vide, et que vous utilisez la même valeur <a class="header-anchor" href="#etape-3-confirmer-que-api-key-n-est-pas-vide-et-que-vous-utilisez-la-meme-valeur" aria-label="Permalink to &quot;Étape 3 : Confirmer que `api_key` n&#39;est pas vide, et que vous utilisez la même valeur&quot;">​</a></h3><p><strong>Pourquoi</strong> Quand l&#39;authentification est activée, si <code>proxy.api_key</code> est vide, <code>auth_middleware()</code> refusera directement toutes les requêtes et enregistrera une erreur.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Proxy auth is enabled but api_key is empty; denying request</span></span></code></pre></div><p><strong>Ce que vous devriez voir</strong></p><ul><li>Dans la page API Proxy, vous pouvez voir une clé commençant par <code>sk-</code> (la valeur par défaut dans <code>ProxyConfig::default()</code> est générée automatiquement)</li><li>Après avoir cliqué sur « Regenerate/Modifier » et enregistré, les requêtes externes sont immédiatement validées selon la nouvelle clé (pas besoin de redémarrer)</li></ul><hr><h3 id="etape-4-essayez-avec-l-en-tete-le-plus-simple-n-utilisez-pas-de-sdk-complexes-d-abord" tabindex="-1">Étape 4 : Essayez avec l&#39;en-tête le plus simple (n&#39;utilisez pas de SDK complexes d&#39;abord) <a class="header-anchor" href="#etape-4-essayez-avec-l-en-tete-le-plus-simple-n-utilisez-pas-de-sdk-complexes-d-abord" aria-label="Permalink to &quot;Étape 4 : Essayez avec l&#39;en-tête le plus simple (n&#39;utilisez pas de SDK complexes d&#39;abord)&quot;">​</a></h3><p><strong>Pourquoi</strong> Le middleware lira d&#39;abord <code>Authorization</code>, puis <code>x-api-key</code>, enfin <code>x-goog-api-key</code>. Si vous envoyez plusieurs en-têtes en même temps, le premier est faux, même si le second est correct, il ne sera pas utilisé.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Méthode recommandée : Authorization + Bearer</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/v1/models</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer sk-REPLACE_WITH_YOUR_PROXY_API_KEY&quot;</span></span></code></pre></div><p><strong>Ce que vous devriez voir</strong> : <code>HTTP/1.1 200 OK</code> (ou au moins plus 401)</p><div class="info custom-block"><p class="custom-block-title">Détails de compatibilité du proxy avec Authorization</p><p><code>auth_middleware()</code> dépouillera la valeur de <code>Authorization</code> selon le préfixe <code>Bearer </code> ; si pas de préfixe <code>Bearer </code>, il traitera la valeur entière comme clé à comparer. La documentation recommande toujours <code>Authorization: Bearer &lt;key&gt;</code> (plus conforme aux conventions générales SDK).</p></div><p><strong>Si vous devez utiliser <code>x-api-key</code></strong> :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/v1/models</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;x-api-key: sk-REPLACE_WITH_YOUR_PROXY_API_KEY&quot;</span></span></code></pre></div><hr><h2 id="pieges-courants-tous-se-produisent-reellement-dans-le-code-source" tabindex="-1">Pièges courants (tous se produisent réellement dans le code source) <a class="header-anchor" href="#pieges-courants-tous-se-produisent-reellement-dans-le-code-source" aria-label="Permalink to &quot;Pièges courants (tous se produisent réellement dans le code source)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Phénomène</th><th>Vraie cause</th><th>Comment corriger</th></tr></thead><tbody><tr><td><code>auth_mode=auto</code>, mais l&#39;appel local renvoie toujours 401</td><td><code>allow_lan_access=true</code> fait que <code>auto</code> prend effet comme <code>all_except_health</code></td><td>Désactivez <code>allow_lan_access</code>, ou faites porter une clé au client</td></tr><tr><td>Vous pensez « j&#39;ai bien porté x-api-key », mais toujours 401</td><td>Portez simultanément un <code>Authorization</code> non correspondant, le middleware le privilégie</td><td>Supprimez l&#39;en-tête en trop, ne gardez qu&#39;un que vous êtes sûr correct</td></tr><tr><td><code>Authorization: Bearer&lt;key&gt;</code> toujours 401</td><td>Il manque un espace après <code>Bearer</code>, impossible de dépouiller selon le préfixe <code>Bearer </code></td><td>Changez en <code>Authorization: Bearer &lt;key&gt;</code></td></tr><tr><td>Toutes les requêtes renvoient 401, le journal affiche <code>api_key is empty</code></td><td><code>proxy.api_key</code> est vide</td><td>Dans le GUI, régénérez/définissez une clé non vide</td></tr></tbody></table><h2 id="resume-de-la-lecon" tabindex="-1">Résumé de la leçon <a class="header-anchor" href="#resume-de-la-lecon" aria-label="Permalink to &quot;Résumé de la leçon&quot;">​</a></h2><ul><li>Utilisez d&#39;abord <code>/healthz</code> pour localiser si 401 provient de la couche d&#39;authentification du proxy</li><li>Ensuite confirmez <code>auth_mode</code> (surtout le mode effectif de <code>auto</code>)</li><li>Enfin ne portez qu&#39;un en-tête sûr et correct pour vérifier (évitez les pièges de priorité des en-têtes)</li></ul><h2 id="prochaine-lecon" tabindex="-1">Prochaine leçon <a class="header-anchor" href="#prochaine-lecon" aria-label="Permalink to &quot;Prochaine leçon&quot;">​</a></h2><blockquote><p>La prochaine leçon, nous apprendrons <strong><a href="./../429-rotation/">429/Erreur de capacité : attentes correctes pour la rotation des comptes et méprise sur l&#39;épuisement de la capacité du modèle</a></strong>.</p><p>Vous apprendrez :</p><ul><li>Si 429 est « quota insuffisant » ou « limitation en amont »</li><li>Attentes correctes pour la rotation des comptes (quand basculer automatiquement, quand ne pas basculer)</li><li>Utiliser la configuration pour réduire la probabilité de 429</li></ul></blockquote><hr><h2 id="annexe-reference-du-code-source" tabindex="-1">Annexe : Référence du code source <a class="header-anchor" href="#annexe-reference-du-code-source" aria-label="Permalink to &quot;Annexe : Référence du code source&quot;">​</a></h2><details><summary><strong>Cliquez pour voir l&#39;emplacement du code source</strong></summary><blockquote><p>Heure de mise à jour : 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Fonction</th><th>Chemin du fichier</th><th>Ligne</th></tr></thead><tbody><tr><td>Énumération ProxyAuthMode</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L5-L18" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>5-18</td></tr><tr><td>ProxyConfig: allow_lan_access/auth_mode/api_key et valeurs par défaut</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L174-L258" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>174-258</td></tr><tr><td>Analyse du mode auto (effective_auth_mode)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/security.rs#L1-L30" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/security.rs</code></a></td><td>1-30</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Enregistrement de route /healthz et ordre des middlewares</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L170-L193" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></td><td>170-193</td></tr><tr><td>Documentation d&#39;authentification (modes et conventions client)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/proxy/auth.md#L1-L45" target="_blank" rel="noreferrer"><code>docs/proxy/auth.md</code></a></td><td>1-45</td></tr></tbody></table><p><strong>Énumérations clés</strong> :</p><ul><li><code>ProxyAuthMode::{Off, Strict, AllExceptHealth, Auto}</code> : modes d&#39;authentification</li></ul><p><strong>Fonctions clés</strong> :</p><ul><li><code>ProxySecurityConfig::effective_auth_mode()</code> : analyser <code>auto</code> en vraie stratégie</li><li><code>auth_middleware()</code> : exécuter l&#39;authentification (incluant l&#39;ordre d&#39;extraction des en-têtes et exemption /healthz)</li></ul></details>',45)])])}const m=t(r,[["render",s]]);export{h as __pageData,m as default};
